package email

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"strings"
	"time"

	gm "google.golang.org/api/gmail/v1"
)

type RawMessage struct {
	ID          string
	ThreadID    string
	Subject     string
	FromEmail   string
	ToEmails    string // JSON array
	CcEmails    string // JSON array
	Date        string
	Snippet     string
	BodyPreview string
	Labels      string // JSON array
}

type SyncResult struct {
	Fetched  int
	Stored   int
	Cursor   string
	Duration time.Duration
}

func Sync(srv *gm.Service, d *sql.DB) (*SyncResult, error) {
	start := time.Now()
	result := &SyncResult{}

	var cursor string
	d.QueryRow("SELECT sync_cursor FROM connectors WHERE id = 'gmail'").Scan(&cursor)

	query := "in:sent"
	if cursor == "" {
		since := time.Now().AddDate(0, 0, -90).Format("2006/01/02")
		query += " after:" + since
	}

	var pageToken string
	for {
		req := srv.Users.Messages.List("me").Q(query).MaxResults(100)
		if pageToken != "" {
			req = req.PageToken(pageToken)
		}

		resp, err := req.Do()
		if err != nil {
			return result, fmt.Errorf("listing messages: %w", err)
		}

		for _, msg := range resp.Messages {
			result.Fetched++

			if cursor != "" {
				var exists int
				d.QueryRow("SELECT 1 FROM emails WHERE id = ?", msg.Id).Scan(&exists)
				if exists == 1 {
					continue
				}
			}

			full, err := srv.Users.Messages.Get("me", msg.Id).Format("metadata").
				MetadataHeaders("Subject", "From", "To", "Cc", "Date").Do()
			if err != nil {
				fmt.Printf("  warning: skipping message %s: %v\n", msg.Id, err)
				continue
			}

			email := parseMessage(full)
			if err := StoreEmail(d, email); err != nil {
				fmt.Printf("  warning: storing message %s: %v\n", msg.Id, err)
				continue
			}
			result.Stored++
		}

		pageToken = resp.NextPageToken
		if pageToken == "" {
			break
		}
	}

	result.Cursor = time.Now().UTC().Format(time.RFC3339)
	result.Duration = time.Since(start)

	d.Exec(
		`INSERT INTO connectors (id, type, sync_cursor, last_sync_at, total_synced)
		 VALUES ('gmail', 'email', ?, ?, ?)
		 ON CONFLICT(id) DO UPDATE SET sync_cursor = ?, last_sync_at = ?, total_synced = total_synced + ?`,
		result.Cursor, result.Cursor, result.Stored,
		result.Cursor, result.Cursor, result.Stored,
	)

	return result, nil
}

func StoreEmail(d *sql.DB, e *RawMessage) error {
	_, err := d.Exec(`
		INSERT INTO emails (id, thread_id, subject, from_email, to_emails, cc_emails, date, snippet, body_preview, labels)
		VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
		ON CONFLICT(id) DO UPDATE SET
			subject = excluded.subject,
			snippet = excluded.snippet,
			body_preview = excluded.body_preview,
			labels = excluded.labels,
			synced_at = datetime('now')`,
		e.ID, e.ThreadID, e.Subject, e.FromEmail, e.ToEmails, e.CcEmails,
		e.Date, e.Snippet, e.BodyPreview, e.Labels,
	)
	return err
}

func parseMessage(msg *gm.Message) *RawMessage {
	e := &RawMessage{
		ID:       msg.Id,
		ThreadID: msg.ThreadId,
		Snippet:  msg.Snippet,
		CcEmails: "[]",
		ToEmails: "[]",
		Labels:   "[]",
	}

	for _, h := range msg.Payload.Headers {
		switch h.Name {
		case "Subject":
			e.Subject = h.Value
		case "From":
			e.FromEmail = extractEmail(h.Value)
		case "To":
			e.ToEmails = emailsToJSON(h.Value)
		case "Cc":
			e.CcEmails = emailsToJSON(h.Value)
		case "Date":
			if t, err := time.Parse(time.RFC1123Z, h.Value); err == nil {
				e.Date = t.UTC().Format(time.RFC3339)
			} else if t, err := time.Parse("Mon, 2 Jan 2006 15:04:05 -0700", h.Value); err == nil {
				e.Date = t.UTC().Format(time.RFC3339)
			} else {
				e.Date = h.Value
			}
		}
	}

	if len(msg.LabelIds) > 0 {
		labelsJSON, _ := json.Marshal(msg.LabelIds)
		e.Labels = string(labelsJSON)
	}

	return e
}

func extractEmail(header string) string {
	if i := strings.Index(header, "<"); i != -1 {
		if j := strings.Index(header, ">"); j != -1 {
			return header[i+1 : j]
		}
	}
	return strings.TrimSpace(header)
}

func emailsToJSON(header string) string {
	if header == "" {
		return "[]"
	}
	parts := strings.Split(header, ",")
	emails := make([]string, 0, len(parts))
	for _, p := range parts {
		emails = append(emails, extractEmail(p))
	}
	data, _ := json.Marshal(emails)
	return string(data)
}

package account

import (
	"crypto/rand"
	"fmt"
	"math/big"
	"os"
	"time"

	"github.com/usenurge/nurgesh/internal/util"
)

const (
	loginTimeout = 120 * time.Second
)

// EnsureAuth checks for a valid auth token. If not found,
// runs the interactive browser login flow.
// Trusts the local token if it exists — only re-auths when no token is present
// or when an API call rejects it downstream.
// All status messages are printed to stderr so stdout stays clean for --format json.
func EnsureAuth(convexURL, dashboardURL string) (*User, error) {
	af, err := LoadAuth()
	if err == nil && af.Token != "" {
		return &User{Email: af.Email, Name: af.Name}, nil
	}

	// No valid token — start login flow
	return Login(convexURL, dashboardURL)
}

// Login runs the interactive browser-based login flow.
func Login(convexURL, dashboardURL string) (*User, error) {
	// Generate state parameter
	state := generateState()

	// Start local callback server (binds before opening browser)
	port, resultCh, errCh, cleanup, err := util.ListenAndWait(loginTimeout)
	if err != nil {
		return nil, fmt.Errorf("starting callback server: %w", err)
	}
	defer cleanup()

	// Open browser to dashboard
	authURL := fmt.Sprintf("%s/cli-auth?port=%d&state=%s", dashboardURL, port, state)
	fmt.Fprintf(os.Stderr, "  Opening browser to log in...\n")
	if err := util.OpenBrowser(authURL); err != nil {
		fmt.Fprintf(os.Stderr, "  Could not open browser. Please visit:\n  %s\n", authURL)
	}

	// Wait for callback
	select {
	case result := <-resultCh:
		// Verify state
		if result.Values.Get("state") != state {
			return nil, fmt.Errorf("state mismatch — possible CSRF attack")
		}

		code := result.Values.Get("code")
		if code == "" {
			return nil, fmt.Errorf("no auth code received")
		}

		// Exchange code for token
		client := NewConvexClient(convexURL)
		resp, err := client.ExchangeCode(code)
		if err != nil {
			return nil, fmt.Errorf("exchanging auth code: %w", err)
		}

		// Save auth file
		now := time.Now().UTC().Format(time.RFC3339)
		af := &AuthFile{
			Token:       resp.Token,
			Email:       resp.Email,
			Name:        resp.Name,
			CreatedAt:   now,
			ValidatedAt: now,
		}
		if err := SaveAuth(af); err != nil {
			return nil, fmt.Errorf("saving auth: %w", err)
		}

		fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Logged in as %s\n", resp.Email)
		return &User{Email: resp.Email, Name: resp.Name}, nil

	case err := <-errCh:
		return nil, err
	}
}

// Logout revokes the token and deletes local auth file.
func Logout(convexURL string) error {
	af, err := LoadAuth()
	if err != nil {
		return fmt.Errorf("not logged in")
	}

	// Revoke on server (best effort)
	client := NewConvexClient(convexURL)
	_ = client.RevokeToken(af.Token)

	// Delete local auth file
	if err := DeleteAuth(); err != nil {
		return fmt.Errorf("deleting auth file: %w", err)
	}

	fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Logged out\n")
	return nil
}

// generateState creates a cryptographically random state string for CSRF protection.
func generateState() string {
	const chars = "REDACTED"
	b := make([]byte, 32)
	for i := range b {
		n, _ := rand.Int(rand.Reader, big.NewInt(int64(len(chars))))
		b[i] = chars[n.Int64()]
	}
	return string(b)
}
